VALUES
  ('social-worker-moex-02191', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '以下有關Fred Fiedler權變領導理論（contingency leadership theory）說明，何項有誤？', '["個人的基本領導風格是影響領導成敗的主因", "該模式假設個人的領導風格是固定的", "關係導向的領導者在低控制情境下績效表現最好", "領導者與部屬關係愈好，職位權力愈強，則領導者的控制力與影響力愈大"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "a074978a4189", "answer_pdf_sha1": "a21ae17ed63d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02192', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關策略管理（strategic management）與策略規劃（strategic planning）的敘述，下列何者錯誤？', '["策略管理必須重視組織全體的策略規劃", "策略管理關注短期趨勢", "策略規劃強調「做出最適度的策略決定」，而策略管理則強調「產生策略上的結果」", "「策略管理」比起「策略規劃」較為廣泛"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "a074978a4189", "answer_pdf_sha1": "a21ae17ed63d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02193', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在方案需求評估中，個案問題（client problems）、個案需求（client needs）、問題成因（causes of problem）， 三者的邏輯順序為何？', '["個案問題→問題成因→個案需求", "個案需求→個案問題→問題成因", "個案問題→個案需求→問題成因", "問題成因→個案問題→個案需求"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "a074978a4189", "answer_pdf_sha1": "a21ae17ed63d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02194', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織識別系統應包含理念識別（Mind Identity）、行為識別（Behavior Identity）及視覺識別（Visual Identity） 三者整合而成，下列何者屬於行為識別？', '["組織定位", "組織標準用色", "品質管制", "創新觀念"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "a074978a4189", "answer_pdf_sha1": "a21ae17ed63d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02195', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '以下那一項不是邏輯模式的缺點？', '["因時間與資源的限制，無法按規劃來執行方案", "規劃內容太抽象，常採用難以理解的專業語言", "因果認定及方案規劃太線性化", "僵硬的規劃，無法反映方案與環境的變化或新訊息"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "a074978a4189", "answer_pdf_sha1": "a21ae17ed63d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02196', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列人力資源管理的工作分析、工作設計之敘述，何者錯誤？', '["工作擴大化是將某項工作的範圍加大，使所從事的工作任務變多，以消除員工工作的單調感", "工作豐富化是改變員工工作內容，主要在擴展工作的廣度，目的在讓員工對自己的工作有較大的控制權", "工作輪調是讓工作人員有機會從事不同的工作，輪流至不同單位工作", "工作分擔指的是建立「工作小組」，使員工有參與感、歸屬感"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "a074978a4189", "answer_pdf_sha1": "a21ae17ed63d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02197', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '以下對招募（recruitment）的描述，何者有誤？', '["招募必須緊扣組織的使命，並契合組織未來的人力需要", "非營利組織一般較常採用內部招募（internal recruiting）來填補職缺", "宜對職缺做工作分析，確認所需人才的KSAOs（知識／技能／能力／其他特質），以利找到適任人選", "求職公告宜詳列工作職務內容、所需人才條件、經歷與教育程度等等"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "a074978a4189", "answer_pdf_sha1": "a21ae17ed63d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02198', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「先調查現有志工的動機和背景，找出之間的共同點，進而從相似群體之中招募新的志工。」這是屬於 何種志工招募方法？', '["暖身招募", "目標招募", "同心圓招募", "團體招募"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "a074978a4189", "answer_pdf_sha1": "a21ae17ed63d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02199', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '就臺灣的非營利組織而言，下列針對非營利組織募款的描述，何者錯誤？', '["在超過募款目標額度之後應給予募款人員一定百分比當績效獎金，將可以增加勸募的動機", "人們會因為對資金貧乏組織的刻板印象而決定不捐款", "有人會因為傳統文化和習慣的因素而決定捐款", "網路募款的重點在發展出安全的網站，包括安全的付款系統與更快的連結時間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "a074978a4189", "answer_pdf_sha1": "a21ae17ed63d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02200', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '針對「財務」與「會計」的敘述，下列何者正確？', '["「財務」著重於歷史活動，忠實地記載已發生的活動", "「會計」重視未來與實際操作", "「會計」以現金流量之評價為核心，以協助做決策", "「財務」著重於「向前看」的觀念，可做為主管決策的重要參考依據之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "a074978a4189", "answer_pdf_sha1": "a21ae17ed63d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
